{
  path = $2;
  bytes = $1;

  # Extract filename from path
  n = split(path, parts, "/");
  filename = parts[n];

  # Extract extension
  if (match(filename, /\.([^.]+)$/)) {
    ext = tolower(substr(filename, RSTART+1));
  } else {
    ext = "NO_EXTENSION";
  }

  total[ext] += bytes;
}
END {
  print "extension,total_bytes";
  for (ext in total) {
    print ext "," total[ext];
  }
}' | (head -1; tail -n +2 | sort -t',' -k2 -rn) > /home/user/reports/extension_summary.csv

